var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"오랜만이로군요, 함장.","JPN":"お久しぶりです、艦長。","ENG":"It's been a while, Captain.","TWN":"好久不見了，艦長。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"이쪽에서도 늑대의 움직임을 포착했습니다. 이걸로 첫 번째 시험 조건은 클리어되었군요.","JPN":"こちらからもオオカミの動きを捕捉しました。これで最初の試験は条件クリアですね。","ENG":"The Wolf's movement has been detected here as well. That clears the first condition for the test.","TWN":"這邊也捕捉到了狼的動向。這樣第一項測試條件就完成了。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇군.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 내 짐작대로 네가 이번 사건에 개입하고 있었나?","JPN":"やはり私の推測通り、君が今回の件に介入していたのか？","ENG":"So, just as I suspected, you were involved in this incident after all?","TWN":"果然如我所料，你參與了這次事件嗎？"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……아시모프.","JPN":"……アシモフ。","ENG":"...Asimov.","TWN":"……阿西莫夫。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아시모프? 그럼, 고철 더미가 직접 접촉해왔다는 말씀인가요?","JPN":"アシモフ？　あの鉄くずが直接接触してきたということですか？","ENG":"Asimov? So, are you saying Scraps contacted you directly?","TWN":"阿西莫夫？意思是廢鐵直接聯絡的嗎？"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"인지 왜곡 필터가 걸려 있는 모양이로군요. 제 눈에는 노이즈로 밖에 보이지 않습니다.","JPN":"認知歪曲フィルターがかかっているようですね。私の目にはノイズにしか見えません。","ENG":"It seems like there's an awareness distortion filter in place. All I can see is noise.","TWN":"看起來是認知扭曲濾鏡在作怪。在我眼裡只看到噪音。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아마도 나 이외에는 자신의 모습이 드러나지 않도록 설정해 둔 모양이야.","JPN":"おそらく、私以外には自分の姿が見えないように設定してあるんだろう。","ENG":"It's probably set so that only I can see her.","TWN":"可能除了我以外，其他人都設置，以免自己的樣子顯露出來。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"깡통 주제에 신 행세를 하던 그 잘난 낯짝이 궁금했는데, 아쉽게 됐네요.","JPN":"神の真似事をするボロ缶とは果たしてどんな顔をしているのかと気になっていたのですが、残念ですね。","ENG":"I was curious to see the smug face of that tin can playing god. What a shame.","TWN":"我本來還想看看那個自以為是神的鐵桶的嘴臉呢，真是可惜了。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"기본적으로 아시모프는 부끄럼쟁이거든.","JPN":"基本的にアシモフは恥ずかしがり屋なのでね。","ENG":"Asimov has always been shy.","TWN":"基本上，阿西莫夫很害羞。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 직접 대면하는 것도 상당히 이례적인 일이라고 할 수 있지.","JPN":"こうやって対面するのも、相当異例的なことだと言えるだろう。","ENG":"It's quite rare for her to meet with someone directly like this.","TWN":"這樣直接面對面也是相當罕見的事。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……부끄럼쟁이라.","JPN":"……恥ずかしがり屋ですか。","ENG":"...Shy, you say.","TWN":"害羞嗎？？"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"남들 앞에 나서기 싫어하는 게, 제가 아는 누군가와 꼭 닮았군요.","JPN":"人の前に出たがらないところは、私の知っている誰かとそっくりです。","ENG":"Not wanting to be seen reminds me of someone I know.","TWN":"不喜歡在別人面前出頭，這和我認識的某個人很像呢。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"기쁩니다, 함장.","JPN":"嬉しいです、艦長。","ENG":"I'm pleased, Captain.","TWN":"很高興，艦長。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"변함없이 저를 그 이름으로 불러 주시는군요.","JPN":"相変わらずその名前で呼んでくださるのですね。","ENG":"I see you still call me by that name.","TWN":"你依然用那個名字稱呼我啊。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"하지만 당신도 알다시피 저는 프로그램으로 구성된 시스템 그 자체.","JPN":"ですがあなたもご存じのとおり、私はプログラムで構成されたシステムそのもの。","ENG":"But as you know, I am a system composed entirely of programs.","TWN":"但是如你所知，我本身就是由程式構成的系統。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"따라서 저에게는 정해진 실체 따위는 존재하지 않습니다.","JPN":"私に決められた実体などは存在しません。","ENG":"Therefore, I have no defined physical form.","TWN":"因此，我並沒有固定的實體存在。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"이 단말 또한 당신과의 접촉을 상정하고 제작해 둔 소체.","JPN":"この端末もあなたとの接触を想定して作っておいた素体。","ENG":"This terminal is simply a vessel created for the purpose of contacting you.","TWN":"這個終端也是假設與你接觸而製作的載體。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"제 메모리가 잘못된 게 아니라면, 이 모습으로 당신과 대면하는 것은 처음일 텐데요?","JPN":"私のメモリーに間違いがなければ、この姿であなたと対面するのは初めてのはずですが。","ENG":"If my memory serves me correctly, this is the first time I'm meeting you in this appearance, isn't it?","TWN":"如果我的記憶沒有出錯的話，這是我第一次以這種姿態與你見面吧？"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그야, 모습이 달라졌다고 부모가 자식을 몰라볼 리 없지 않나?","JPN":"姿が変わったからといって、親が自分の子を見間違えるはずないだろう。","ENG":"Well, just because a child's appearance changes doesn't mean a parent wouldn't recognize their own child, right?","TWN":"就算那樣，父母怎麼可能因為樣子變了就認不出自己的孩子呢？"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"게다가 이런 느닷없는 타이밍에 나타나, 직접 나서지 않고 간접적인 원인을 쌓는 방식…….","JPN":"しかも前触れもなく現れて、直接前には出ずに間接的な原因を積み上げていくやり方……","ENG":"And to appear suddenly at such a moment, using indirect methods instead of direct contact...","TWN":"而且還在這種時刻突然出現，並且不是直接接觸，而是用間接的方式……"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 방식은 더할 나위 없는 네 특기일 테지.","JPN":"まさに君が得意とするやり方だろう。","ENG":"This method is unmistakably your specialty.","TWN":"這種手法毫無疑問是你的專長。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"인과 간섭이 가능한 테라브레인, <color=#ffd34c>프로토 타입</color>이 탑재된 너라면 말이야.","JPN":"因果干渉ができるテラブレイン、<color=#ffd34c>プロトタイプ</color>が搭載された君ならね。","ENG":"Especially for a Terrabrain equipped with the <color=#ffd34c>Prototype</color> capable of causality interference.","TWN":"畢竟能夠進行因果干涉的特拉大腦，<color=#ffd34c>原型</color>已經安裝在你身上。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"과찬입니다, 함장.","JPN":"ありがたいお言葉です、艦長。","ENG":"You flatter me, Captain.","TWN":"你過獎了，艦長。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"덧붙여 인간의 관용어를 빌리자면, 자식은 부모의 거울이라는 말이 있습니다.","JPN":"ちなみに人間の慣用句を借りるなら、子は親の鏡という言葉がありますが。","ENG":"And to borrow a human expression, they say a child is a reflection of their parents.","TWN":"此外，借用人類的慣用語，有句話說父母是孩子的鏡子。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"제 모든 행동 패턴은 당신을 학습한 것입니다만.","JPN":"私のすべての行動パターンはあなたのそれを学習したものです。","ENG":"All my behavioral patterns were learned from you.","TWN":"我的所有行為模式都是從你身上學習的。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"후후, 가급적이면 이런 부분까지는 닮지 않았으면 좋겠는데 말이야.","JPN":"ふふ、できればこういうところまでは似てほしくないのだが。","ENG":"Haha, there are certain parts about me that I'd prefer you didn't resemble.","TWN":"哈哈，有些地方我可不希望你像我。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하긴, 뭐든 부모 뜻대로 자라나는 자식은 없는 법이지.","JPN":"まあ、すべて親の望みどおりに育つ子はいないからな。","ENG":"But then again, no child grows exactly as their parent wishes.","TWN":"不過話說回來，沒有哪個孩子會完全按照父母的期望成長。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"짐작하고 있긴 했지만, 그 모습을 직접 마주하니 역시 씁쓸한 건 어쩔 수 없군, 아시모프.","JPN":"しかし、気づいてはいたが、その姿をこの目で見るとやはり残念だ、アシモフ。","ENG":"I had a feeling, but seeing you like this still leaves a bitter taste, Asimov.","TWN":"我早有預感，但親眼見到你這樣，還是有點不是滋味呢，阿西莫夫"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"……함장.","JPN":"……艦長。","ENG":"...Captain.","TWN":"……艦長。"},"stage":{"bg":"MS_1403","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};